function normalizeReleaseNote(vendor, rawData) {
  return {
    vendor: vendor,
    product: rawData.product || vendor,
    type: rawData.type || 'release',
    version: rawData.version || 'unknown',
    severity: rawData.severity || (rawData.type === 'deprecation' ? 'high' : 'low'),
    url: rawData.url || rawData.link,
    timestamp: new Date().toISOString()
  };
}
